    const email = document.getElementById('exampleInputEmail').value.trim();
    const password = document.getElementById('examplePasswordInput').value;
    const confirmPassword = document.getElementById('exampleRepeatPasswordInput').value;

    // Validation
    if (!firstName || !lastName || !email || !password || !confirmPassword) {
        Swal.fire({
            icon: 'warning',
            title: 'Missing Information',
            text: 'Please fill in all fields',
            confirmButtonColor: '#4e73df'
        });
        return;
    }

    if (!isValidEmail(email)) {
        Swal.fire({
            icon: 'error',
            title: 'Invalid Email',
            text: 'Please enter a valid email address',
            confirmButtonColor: '#4e73df'
        });
        return;
    }

    if (password.length < 6) {
        Swal.fire({
            icon: 'warning',
            title: 'Weak Password',
            text: 'Password must be at least 6 characters long',
            confirmButtonColor: '#4e73df'
        });
        return;
    }

    if (password !== confirmPassword) {
        Swal.fire({
            icon: 'error',
            title: 'Password Mismatch',
            text: 'Passwords do not match',
            confirmButtonColor: '#4e73df'
        });
        return;
    }

    // Check if user already exists
    const users = getUsers();
    if (users[email]) {
        Swal.fire({
            icon: 'error',
            title: 'Account Exists',
            text: 'An account with this email already exists',
            confirmButtonColor: '#4e73df'
        });
        return;
    }

    // Save user
    users[email] = {
        firstName,
        lastName,
        email,
        password: btoa(password), // Simple encoding (not secure for production)
        createdAt: new Date().toISOString()
    };

    localStorage.setItem('users', JSON.stringify(users));

    Swal.fire({
        icon: 'success',
        title: 'Account Created!',
        text: 'Your account has been created successfully. Please login.',
        confirmButtonColor: '#4e73df',
        confirmButtonText: 'Go to Login'
    }).then(() => {
        window.location.href = 'login.html';
    });
}

