function logActivity(userId, action, module, details) {
    const logs = getActivityLogs();
    const log = {
        id: 'LOG-' + Date.now(),
        userId: userId,
        action: action,
        module: module,
        details: details,
        timestamp: new Date().toISOString(),
        ipAddress: 'N/A' // Client-side limitation
    };

    logs.push(log);
    localStorage.setItem('activityLogs', JSON.stringify(logs));
}

