function loadUsersTable() {
    const users = getUsers();
    const userTableBody = document.getElementById('userTableBody');

    if (!userTableBody) return;

    // Convert users object to array
    const usersArray = Object.values(users);

    if (usersArray.length === 0) {
        userTableBody.innerHTML = '<tr><td colspan="6" class="text-center">No staff registered yet</td></tr>';
        document.getElementById('dataTable_info').textContent = 'Showing 0 to 0 of 0';
        return;
    }

    // Clear existing rows
    userTableBody.innerHTML = '';

    // Generate table rows
    usersArray.forEach((user, index) => {
        const row = document.createElement('tr');

        // Format hired date
        const hiredDate = new Date(user.dateHired || user.createdAt);
        const formattedDate = hiredDate.toLocaleDateString('en-US', {
            year: 'numeric',
            month: '2-digit',
            day: '2-digit'
        });

        // Role badge colors
        const roleBadgeClass = {
            'admin': 'badge bg-danger',
            'secretary': 'badge bg-primary',
            'staff': 'badge bg-secondary'
        };

        const roleClass = roleBadgeClass[user.role] || 'badge bg-secondary';
        const statusBadge = user.isActive ? 
            '<span class="badge bg-success">Active</span>' : 
            '<span class="badge bg-warning">Inactive</span>';

        const profilePhoto = user.profilePhoto || 'assets/img/avatars/avatar1.jpeg';
        const position = user.position || 'Not specified';

        row.innerHTML = `
            <td><img class="rounded-circle me-2" width="30" height="30" src="${profilePhoto}">${user.firstName} ${user.lastName}</td>
            <td><span class="${roleClass}">${user.role.toUpperCase()}</span></td>
            <td>${position}</td>
            <td>${statusBadge}</td>
            <td>${formattedDate}</td>
            <td>${user.email}</td>
        `;

        userTableBody.appendChild(row);
    });

    // Update info text
    document.getElementById('dataTable_info').textContent = `Showing 1 to ${usersArray.length} of ${usersArray.length}`;
}

