            </div>
        `,
        width: 600,
        confirmButtonColor: '#4e73df'
    });
}

// Print certificate
function printCertificate(certId) {
    const cert = getCertificates()[certId];
    const resident = getResidents()[cert.residentId];

    if (!cert || !resident || cert.status !== 'completed') {
        Swal.fire({
            icon: 'error',
