+            const counts = {
+                clearance: 0,
+                residency: 0,
+                indigency: 0,
+                job_seeker: 0
+            };
+            
+            certificates.forEach(cert => {
+                if (counts.hasOwnProperty(cert.certificateType)) {
+                    counts[cert.certificateType]++;
+                }
