+            // Update counts and progress bars
+            Object.keys(counts).forEach(type => {
+                const percentage = (counts[type] / total) * 100;
+                const typeKey = type === 'job_seeker' ? 'JobSeeker' : type.charAt(0).toUpperCase() + type.slice(1);
